if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const h = $input.first().json.headers || {};
const b = $input.first().json.body || {};
const auth = h['x-gda-auth'] || h['x-gda-key'] || b.auth_key || '';
const origin = (h.origin || h.referer || '').toLowerCase();
const trusted = ['gda.csr-llc.tech','n8n.csr-llc.tech','localhost'];
if (auth !== $env.GDA_API_KEY_2026 && !trusted.some(o => origin.includes(o))) throw new Error('Unauthorized');
return $input.all();

